const newsResponse = $('Get Latest News').first().json;
const summary = $('Get Daily Summary').first().json;
const chartUrl = 'https://btc-oracle-production.up.railway.app/api/charts/prediction-card.png?timeframe=1h&size=twitter';

// Pick the most relevant/recent news item
const articles = newsResponse.articles || newsResponse.data || newsResponse;
const topNews = Array.isArray(articles) ? articles[0] : articles;

if (!topNews || !topNews.title) {
  return [{ json: { skip: true, reason: 'No news available' } }];
}

const prompt = `Here's a crypto news headline: '${topNews.title}'${topNews.description ? '\nSummary: ' + topNews.description : ''}

And here's BTC Seer's current prediction data:
${JSON.stringify(summary, null, 2)}

A prediction chart image is available at: ${chartUrl}
Include this URL at the end of your tweet so it shows as a preview image.

Write a tweet that adds our AI's perspective to this news. Show how BTC Seer's prediction aligns or contrasts with the news. Max 270 chars (not counting the URL). Include #Bitcoin #BTC. Mention @BTC_Seer_Bot.`;

return [{ json: { skip: false, prompt, newsTitle: topNews.title, chartUrl } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const tweet = $('Extract Tweet Text').first().json.text;
const newsTitle = $('Pick News & Build Prompt').first().json.newsTitle;
const now = new Date().toISOString();
console.log(`[${now}] News quote tweet posted about: ${newsTitle}`);
return [{ json: { status: 'posted', timestamp: now, newsTitle, tweet_length: tweet.length } }];
